import pytest

# Assuming the function is imported from your module:
# from your_module import topological_sort

def is_valid_topological_order(graph: dict, order: list) -> bool:
    """Helper to verify if a list is a valid topological ordering for the given graph."""
    # The implementation only outputs keys present in the graph dict
    if set(order) != set(graph.keys()):
        return False

    pos = {node: i for i, node in enumerate(order)}
    for u, neighbors in graph.items():
        for v in neighbors:
            # Only check ordering for neighbors that are also in the output
            if v in pos and pos[u] > pos[v]:
                return False
    return True


